// Extract trip data
const body = $input.item.json.body || $input.item.json;

// Required field validation
const requiredFields = ['tripId', 'userId', 'userName', 'userEmail', 'tripDetails'];
const missing = requiredFields.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Validate trip details
const tripDetails = body.tripDetails || {};
if (!tripDetails.destination || !tripDetails.startDate || !tripDetails.endDate) {
  throw new Error('Trip must have destination, startDate, and endDate');
}

// Validate dates
const startDate = new Date(tripDetails.startDate);
const endDate = new Date(tripDetails.endDate);
const today = new Date();

if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
  throw new Error('Invalid date format');
}

if (endDate < startDate) {
  throw new Error('End date must be after start date');
}

if (endDate > today) {
  throw new Error('Trip has not ended yet');
}

// Calculate trip duration
const durationDays = Math.ceil((endDate - startDate) / (1000 * 60 * 60 * 24));

if (durationDays > 365) {
  throw new Error('Trip duration exceeds maximum of 365 days');
}

// Normalize photo sources
const photoSources = body.photoSources || {};
const normalizedPhotoSources = {
  googlePhotosAlbumId: photoSources.googlePhotosAlbumId || null,
  includeSharedPhotos: photoSources.includeSharedPhotos !== false,
  dateRange: {
    start: tripDetails.startDate,
    end: tripDetails.endDate
  }
};

// Normalize output preferences
const outputPrefs = body.outputPreferences || {};
const normalizedOutputPrefs = {
  journalStyle: outputPrefs.journalStyle || 'narrative',
  includeMapRoute: outputPrefs.includeMapRoute !== false,
  reviewPlatforms: outputPrefs.reviewPlatforms || ['tripadvisor', 'google'],
  highlightCount: Math.min(outputPrefs.highlightCount || 10, 20),
  privacyLevel: outputPrefs.privacyLevel || 'private'
};

// Build validated trip record
const validatedTrip = {
  // Identifiers
  tripId: body.tripId.trim(),
  userId: body.userId.trim(),
  userName: body.userName.trim(),
  userEmail: body.userEmail.trim().toLowerCase(),

  // Trip details
  destination: tripDetails.destination.trim(),
  startDate: tripDetails.startDate,
  endDate: tripDetails.endDate,
  durationDays,
  tripType: tripDetails.tripType || 'general',
  mainInterests: tripDetails.mainInterests || [],

  // Data sources
  photoSources: normalizedPhotoSources,
  notesLocation: body.notesLocation || {},

  // Output preferences
  outputPreferences: normalizedOutputPrefs,
  deliveryOptions: body.deliveryOptions || { emailPDF: true, saveToDrive: true },

  // Metadata
  processedAt: new Date().toISOString(),
  processingId: `PROC-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  status: 'VALIDATED',
  daysAfterTripEnd: Math.ceil((today - endDate) / (1000 * 60 * 60 * 24))
};

return { json: { validatedTrip } };

const validatedTrip = $('Validate Trip Data').item.json.validatedTrip;
const photosResponse = $input.item.json;

// Extract media items
const mediaItems = photosResponse.mediaItems || [];

if (mediaItems.length === 0) {
  return [{ json: { 
    validatedTrip,
    photos: [],
    photoCount: 0,
    error: 'No photos found for this trip'
  }}];
}

// Process each photo
const photos = mediaItems.map((photo, index) => {
  const metadata = photo.mediaMetadata || {};
  const creationTime = new Date(metadata.creationTime || photo.creationTime);

  return {
    photoId: photo.id,
    filename: photo.filename,
    mimeType: photo.mimeType,
    baseUrl: photo.baseUrl,
    productUrl: photo.productUrl,

    // Metadata
    creationTime: creationTime.toISOString(),
    width: metadata.width,
    height: metadata.height,

    // Location data
    location: metadata.location || null,

    // Camera info
    cameraInfo: {
      cameraMake: metadata.photo?.cameraMake || 'Unknown',
      cameraModel: metadata.photo?.cameraModel || 'Unknown',
      focalLength: metadata.photo?.focalLength || null,
      apertureFNumber: metadata.photo?.apertureFNumber || null,
      isoEquivalent: metadata.photo?.isoEquivalent || null
    },

    // Processing metadata
    photoIndex: index,
    downloadUrl: `${photo.baseUrl}=w2048-h2048`,
    thumbnailUrl: `${photo.baseUrl}=w400-h400`
  };
});

// Sort photos chronologically
photos.sort((a, b) => new Date(a.creationTime) - new Date(b.creationTime));

// Calculate statistics
const photosWithLocation = photos.filter(p => p.location).length;
const uniqueDays = new Set(photos.map(p => p.creationTime.split('T')[0])).size;

return [{ json: {
  validatedTrip,
  photos,
  photoStats: {
    totalPhotos: photos.length,
    photosWithLocation,
    locationCoverage: Math.round((photosWithLocation / photos.length) * 100),
    uniqueDays,
    avgPhotosPerDay: Math.round(photos.length / uniqueDays),
    dateRange: {
      first: photos[0]?.creationTime,
      last: photos[photos.length - 1]?.creationTime
    }
  }
}}];

const validatedTrip = $('Validate Trip Data').item.json.validatedTrip;
const notesData = $input.all().map(i => i.json);

// Filter notes for this specific trip
const tripNotes = notesData.filter(note => 
  note.tripId === validatedTrip.tripId ||
  (note.userId === validatedTrip.userId && 
   new Date(note.date) >= new Date(validatedTrip.startDate) &&
   new Date(note.date) <= new Date(validatedTrip.endDate))
);

// Sort notes by date
tripNotes.sort((a, b) => new Date(a.date) - new Date(b.date));

// Organize notes by day
const notesByDay = {};
tripNotes.forEach(note => {
  const dateKey = note.date.split('T')[0];
  if (!notesByDay[dateKey]) {
    notesByDay[dateKey] = [];
  }
  notesByDay[dateKey].push({
    time: note.time || 'all-day',
    content: note.content || note.note || '',
    location: note.location || null,
    tags: note.tags ? note.tags.split(',').map(t => t.trim()) : [],
    mood: note.mood || 'neutral',
    highlights: note.highlights || false
  });
});

// Extract key information
const allTags = [...new Set(tripNotes.flatMap(n => 
  n.tags ? n.tags.split(',').map(t => t.trim()) : []
))];

const mentionedPlaces = [...new Set(tripNotes
  .filter(n => n.location)
  .map(n => n.location)
)];

const highlightNotes = tripNotes.filter(n => n.highlights);

return [{ json: {
  validatedTrip,
  tripNotes: {
    byDay: notesByDay,
    all: tripNotes,
    stats: {
      totalNotes: tripNotes.length,
      daysWithNotes: Object.keys(notesByDay).length,
      tags: allTags,
      mentionedPlaces,
      highlightCount: highlightNotes.length
    }
  }
}}];

const photoData = $('Extract Photo Metadata').item.json;
const notesData = $('Process Trip Notes').item.json;

const validatedTrip = photoData.validatedTrip;
const photos = photoData.photos;
const photoStats = photoData.photoStats;
const tripNotes = notesData.tripNotes;

// Organize photos by day
const photosByDay = {};
photos.forEach(photo => {
  const dateKey = photo.creationTime.split('T')[0];
  if (!photosByDay[dateKey]) {
    photosByDay[dateKey] = [];
  }
  photosByDay[dateKey].push(photo);
});

// Create day-by-day timeline
const timeline = [];
const allDates = [...new Set([...Object.keys(photosByDay), ...Object.keys(tripNotes.byDay)])];
allDates.sort();

allDates.forEach(date => {
  const dayPhotos = photosByDay[date] || [];
  const dayNotes = tripNotes.byDay[date] || [];

  timeline.push({
    date,
    dayNumber: timeline.length + 1,
    photos: dayPhotos,
    photoCount: dayPhotos.length,
    notes: dayNotes,
    noteCount: dayNotes.length,
    locations: [...new Set([
      ...dayPhotos.filter(p => p.location).map(p => p.location),
      ...dayNotes.filter(n => n.location).map(n => n.location)
    ])]
  });
});

// Prepare data for AI analysis
const aiAnalysisInput = {
  validatedTrip,
  timeline,
  statistics: {
    photos: photoStats,
    notes: tripNotes.stats,
    tripDuration: validatedTrip.durationDays,
    totalContent: photos.length + tripNotes.all.length
  },
  rawPhotos: photos,
  rawNotes: tripNotes.all
};

return [{ json: aiAnalysisInput }];

