// Helper function to parse AI response
function parseAIResponse(response) {
  let text = response.response || response.output || response.text || '';

  if (response.content && Array.isArray(response.content)) {
    text = response.content[0]?.text || '';
  }

  const cleanText = text
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  return JSON.parse(cleanText);
}

// Get original merged data
const mergedData = $('Merge Photos & Notes').item.json;

// Parse photo analysis
const photoAnalysisRaw = $('Analyze Photos with Claude Vision').item.json;
const photoAnalysis = parseAIResponse(photoAnalysisRaw);

// Parse journal content
const journalRaw = $('Generate Travel Journal Content').item.json;
const journalContent = parseAIResponse(journalRaw);

// Parse review drafts
const reviewsRaw = $('Generate Platform Review Drafts').item.json;
const reviewDrafts = parseAIResponse(reviewsRaw);

// Build complete memory package
const memoryPackage = {
  // Trip metadata
  tripId: mergedData.validatedTrip.tripId,
  userId: mergedData.validatedTrip.userId,
  userName: mergedData.validatedTrip.userName,
  userEmail: mergedData.validatedTrip.userEmail,
  destination: mergedData.validatedTrip.destination,
  startDate: mergedData.validatedTrip.startDate,
  endDate: mergedData.validatedTrip.endDate,
  durationDays: mergedData.validatedTrip.durationDays,

  // Generated content
  photoAnalysis,
  journal: journalContent,
  reviews: reviewDrafts,

  // Original data references
  photos: mergedData.rawPhotos,
  notes: mergedData.rawNotes,
  timeline: mergedData.timeline,

  // Statistics
  statistics: {
    ...mergedData.statistics,
    highlightPhotosCount: photoAnalysis.highlightPhotos?.length || 0,
    overallQualityScore: photoAnalysis.qualityAssessment?.overallScore || 0
  },

  // Metadata
  generatedAt: new Date().toISOString(),
  processingId: mergedData.validatedTrip.processingId,
  aiModel: 'claude-sonnet-4-20250514',
  status: 'CONTENT_GENERATED'
};

return [{ json: { memoryPackage } }];

const memoryPackage = $input.item.json.memoryPackage;
const highlightPhotos = memoryPackage.photoAnalysis.highlightPhotos || [];
const maxHighlights = memoryPackage.validatedTrip?.outputPreferences?.highlightCount || 10;

// Get top highlights
const topHighlights = highlightPhotos
  .sort((a, b) => b.qualityScore - a.qualityScore)
  .slice(0, maxHighlights);

// Build highlight reel structure
const highlightReel = {
  title: `${memoryPackage.destination} - Best Moments`,
  subtitle: `${memoryPackage.durationDays} days of memories`,
  coverPhoto: memoryPackage.photos[0],

  slides: topHighlights.map((highlight, index) => {
    const photo = memoryPackage.photos[highlight.photoIndex];
    return {
      slideNumber: index + 1,
      photo: {
        url: photo.downloadUrl,
        thumbnail: photo.thumbnailUrl,
        filename: photo.filename
      },
      caption: highlight.caption,
      title: highlight.suggestedTitle,
      description: highlight.significance,
      category: highlight.category,
      mood: highlight.mood,
      date: photo.creationTime.split('T')[0],
      location: photo.location
    };
  }),

  soundtrack: {
    mood: memoryPackage.photoAnalysis.tripAnalysis?.overallMood || 'upbeat',
    suggestions: ['Song suggestion based on mood']
  },

  exportFormats: {
    instagram_story: { duration: 3, format: '1080x1920' },
    instagram_post: { format: '1080x1080' },
    youtube_shorts: { duration: 60, format: '1080x1920' },
    slideshow_video: { duration: 180, format: '1920x1080' }
  },

  statistics: {
    totalHighlights: topHighlights.length,
    averageQuality: Math.round(topHighlights.reduce((sum, h) => sum + h.qualityScore, 0) / topHighlights.length),
    categoriesRepresented: [...new Set(topHighlights.map(h => h.category))],
    moodsRepresented: [...new Set(topHighlights.map(h => h.mood))]
  }
};

return { json: { 
  memoryPackage,
  highlightReel 
}};

const memoryPackage = $input.item.json.memoryPackage;
const highlightReel = $input.item.json.highlightReel;

return {
  json: {
    success: true,
    processingId: memoryPackage.processingId,
    tripId: memoryPackage.tripId,
    destination: memoryPackage.destination,
    generatedAt: memoryPackage.generatedAt,

    summary: {
      totalPhotos: memoryPackage.statistics.photos.totalPhotos,
      highlightPhotos: memoryPackage.statistics.highlightPhotosCount,
      journalPages: memoryPackage.journal.dailyNarratives?.length || 0,
      reviewsDrafted: memoryPackage.reviews.reviews?.length || 0,
      qualityScore: memoryPackage.statistics.overallQualityScore
    },

    topHighlight: highlightReel.slides[0] || null,

    deliverables: {
      journalPDF: 'Available in email attachment',
      highlightsReel: `${highlightReel.slides.length} slides ready`,
      reviews: memoryPackage.reviews.reviews?.map(r => r.platform) || [],
      googleDrive: 'Saved to your Drive folder'
    },

    journalPreview: {
      title: memoryPackage.journal.journalTitle,
      openingLine: memoryPackage.journal.openingReflection?.substring(0, 200) + '...',
      favoriteMemories: memoryPackage.journal.favoriteMemories?.slice(0, 3) || []
    },

    message: `Your ${memoryPackage.destination} travel memories are ready! Check your email for the complete package.`
  }
};

const trips = $input.all().map(i => i.json);
const today = new Date();
const sevenDaysAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter trips that:
// 1. Ended in the last 7 days
// 2. Haven't been processed yet
// 3. Have photo data available
const tripsToProcess = trips.filter(trip => {
  const endDate = new Date(trip.endDate);

  // Skip if trip hasn't ended
  if (endDate > today) return false;

  // Skip if trip ended more than 7 days ago
  if (endDate < sevenDaysAgo) return false;

  // Skip if already processed
  if (trip.memoryPackageGenerated === 'true' || trip.memoryPackageGenerated === true) return false;

  // Skip if no photos indicated
  if (!trip.hasPhotos || trip.photoCount === 0) return false;

  return true;
});

// Create processing jobs
const processingJobs = tripsToProcess.map(trip => ({
  json: {
    body: {
      tripId: trip.tripId,
      userId: trip.userId,
      userName: trip.userName,
      userEmail: trip.userEmail,
      tripDetails: {
        destination: trip.destination,
        startDate: trip.startDate,
        endDate: trip.endDate,
        tripType: trip.tripType || 'general',
        mainInterests: trip.mainInterests?.split(',') || []
      },
      photoSources: {
        googlePhotosAlbumId: trip.googlePhotosAlbumId,
        includeSharedPhotos: true
      },
      notesLocation: {
        googleSheetId: trip.notesSheetId || 'YOUR_GOOGLE_SHEET_ID',
        sheetTab: 'trip_notes'
      },
      outputPreferences: {
        journalStyle: 'narrative',
        includeMapRoute: true,
        reviewPlatforms: ['tripadvisor', 'google', 'instagram'],
        highlightCount: 10,
        privacyLevel: 'private'
      },
      deliveryOptions: {
        emailPDF: true,
        saveToDrive: true
      }
    }
  }
}));

return processingJobs;
